, OBHDKEY
, WBLNO
, SBMTYPECD
, EDICD
, DLVYDIV
, CNTRCTNO
, COLCTREQDAY
, SNDPRSNZIPCD
, SNDPRSNADDR1
, SNDPRSNADDR2
, SNDPRSNNM
, SNDPRSNTELNO
, SNDPRSNTELNO2
, SNDPRSNPICHNM
, RCPPRSNZIPCD
, RCPPRSNADDR1
, RCPPRSNADDR2
, RCPPRSNNM
, RCPPRSNTELNO
, RCPPRSNTELNO2
, RCPPRSNPICHNM
, DLVYMSG
, REPICNM
, BOXQTY
