, ERRCD
, ERRMSG
, SBMSTATUSCD
, SBMERRCD
, SBMSEQ
, CBMDATE
, CBMURKEY
, INSERTDATE
, INSERTURKEY
, UPDATEDATE
, UPDATEURKEY )
VALUES
( #{CTKEY}
, #{OWKEY}
, #{OBHDKEY}
, #{WBLNO}
, #{SBMTYPECD}
, #{EDICD}
, #{DLVYDIV}
, #{CNTRCTNO}
, #{COLCTREQDAY}
, #{SNDPRSNZIPCD}
, #{SNDPRSNADDR1}
, #{SNDPRSNADDR2}
, #{SNDPRSNNM}
, #{SNDPRSNTELNO}
, #{SNDPRSNTELNO2}
, #{SNDPRSNPICHNM}
, #{RCPPRSNZIPCD}
, pkg_crypto$encrypt(#{RCPPRSNADDR1}, #{encKey})
, pkg_crypto$encrypt(#{RCPPRSNADDR2}, #{encKey})
, pkg_crypto$encrypt(#{RCPPRSNNM}, #{encKey})
, pkg_crypto$encrypt(#{RCPPRSNTELNO}, #{encKey})
, pkg_crypto$encrypt(#{RCPPRSNTELNO2}, #{encKey})
, #{RCPPRSNPICHNM}
