, #{BOXTYPE}
, #{MEMO1}
, #{MEMO2}
, #{MEMO3}
, #{MEMO4}
, NULL
, NULL
, NULL
, NULL
, NULL
, NULL
, TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
, #{SURKEY}
, TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
, #{SURKEY}
, TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
, #{SURKEY} )

