UPDATE TWORK_INFO_HANJIN_SBM
   SET SBMSUCCYN = #{O_YN}
	 , SBMSEQ = #{SBMSEQ}
	 , ERRCD = #{O_SQLCODE}
     , ERRMSG = #{O_SQLERRM}
	 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
	 , UPDATEURKEY = #{SURKEY}
 WHERE CTKEY = #{CTKEY}
   AND OWKEY = #{OWKEY}
   AND OBHDKEY = #{OBHDKEY}
   AND WBLNO = #{WBLNO}

UPDATE TWORK_INFO_OB_HD


		SET DLVRYPRGRSTATUSCD = (CASE WHEN #{O_YN} = 'Y' THEN '20' ELSE '98' END)


		SET DLVRYPRGRSTATUSCD = (CASE WHEN #{O_YN} = 'Y' THEN '30' ELSE '98' END)


	 , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP , 'YYYYMMDDHH24MISS')
	 , UPDATEURKEY = #{SURKEY}
 WHERE CTKEY = #{CTKEY}
   AND OWKEY = #{OWKEY}
   AND OBHDKEY = #{OBHDKEY}

